class IsPhoneNumber(DirtyEquals[str]):
    """
    A class that checks if a value is a valid phone number string, optionally checking it against a
    specific country's dialing conventions.

    This is intended as a pragmatic check useful in tests, not a fully compliant phone number parser -
    see [google/libphonenumber](https://github.com/google/libphonenumber) if you need that.
    """

    _clean_re = re.compile(r'[\s\-.()]')

    # (national format, international format) for countries with dedicated rules
    _country_patterns: Dict[str, Tuple[Pattern[str], Pattern[str]]] = {
        'US': (re.compile(r'^\d{10}$'), re.compile(r'^\+1\d{10}$')),
        'GB': (re.compile(r'^0\d{10}$'), re.compile(r'^\+44\d{10}$')),
    }

    _generic_national_re = re.compile(r'^\d{7,15}$')
    _generic_international_re = re.compile(r'^\+\d{7,15}$')

    def __init__(self, country: Optional[str] = None):
        """
        Args:
            country: ISO 3166-1 alpha-2 country code used to apply country-specific validation rules, e.g.
                `'US'` or `'GB'`. If omitted, generic national/international formats are accepted.
                Countries without dedicated rules fall back to generic international format validation
                (`+` followed by 7-15 digits) - the location-specific dialing code is not required for a
                number to be considered valid.

        ```py title="IsPhoneNumber"
        from dirty_equals import IsPhoneNumber

        assert '+1-555-123-4567' == IsPhoneNumber
        assert '555-123-4567' == IsPhoneNumber
        assert '555-123-4567' == IsPhoneNumber('US')
        assert '+1-555-123-4567' == IsPhoneNumber('US')
        assert '020 7946 0958' == IsPhoneNumber('GB')
        assert '+44 20 7946 0958' == IsPhoneNumber('GB')
        assert '555-123-4567' != IsPhoneNumber('GB')
        assert '020 7946 0958' != IsPhoneNumber('US')
        assert '+33 1 42 68 53 00' == IsPhoneNumber('FR')
        assert 123 != IsPhoneNumber
        ```
        """
        self.country = country.upper() if country else None
        super().__init__(plain_repr('*') if country is None else self.country)

    def equals(self, other: Any) -> bool:
        if not isinstance(other, str):
            return False

        cleaned = self._clean_re.sub('', other)
        if not cleaned:
            return False

        if self.country is None:
            if cleaned.startswith('+'):
                return bool(self._generic_international_re.fullmatch(cleaned))
            else:
                return bool(self._generic_national_re.fullmatch(cleaned))

        patterns = self._country_patterns.get(self.country)
        if patterns is None:
            # unsupported country codes fall back to generic international validation
            return bool(self._generic_international_re.fullmatch(cleaned))

        national_re, international_re = patterns
        if cleaned.startswith('+'):
            return bool(international_re.fullmatch(cleaned))
        else:
            return bool(national_re.fullmatch(cleaned))

